using UnityEngine;

/// <summary>
/// Adds a black silhouette outline behind each ParticleSystem on this
/// GameObject by duplicating systems at a slightly larger scale with
/// black vertex color. Attach to any CFXR prefab root.
/// </summary>
public class ParticleOutline : MonoBehaviour
{
    [Header("Outline Settings")]
    [Tooltip(
        "How much larger the outline particles are relative " +
        "to the originals. 1.15 = 15 % bigger."
    )]
    [SerializeField] private float scaleMultiplier = 1.15f;

    [Tooltip("Color of the outline particles.")]
    [SerializeField] private Color outlineColor = Color.black;

    [Tooltip(
        "Sorting-order offset applied to outline systems so " +
        "they render behind the originals."
    )]
    [SerializeField] private int sortingOrderOffset = -1;

    private static bool _isBuilding;

    private void Awake()
    {
        if (_isBuilding)
        {
            Destroy(this);
            return;
        }

        _isBuilding = true;
        BuildOutlines();
        _isBuilding = false;
    }

    private void BuildOutlines()
    {
        ParticleSystem[] systems =
            GetComponentsInChildren<ParticleSystem>(true);

        foreach (ParticleSystem ps in systems)
        {
            CreateOutlineCopy(ps);
        }
    }

    private void CreateOutlineCopy(ParticleSystem original)
    {
        GameObject copy = Instantiate(
            original.gameObject,
            original.transform.parent
        );
        copy.name = original.gameObject.name + " (Outline)";

        StripNestedChildren(copy);
        ApplyOutlineSettings(copy);
    }

    /// <summary>
    /// Remove child particle systems on the copy since they
    /// were already processed individually at the top level.
    /// </summary>
    private static void StripNestedChildren(GameObject root)
    {
        for (int i = root.transform.childCount - 1; i >= 0; i--)
        {
            Destroy(root.transform.GetChild(i).gameObject);
        }
    }

    private void ApplyOutlineSettings(GameObject copy)
    {
        ParticleSystem ps = copy.GetComponent<ParticleSystem>();

        if (ps == null)
        {
            return;
        }

        ParticleSystem.MainModule main = ps.main;
        main.startSize = new ParticleSystem.MinMaxCurve(
            main.startSize.constantMin * scaleMultiplier,
            main.startSize.constantMax * scaleMultiplier
        );
        main.startColor = outlineColor;

        OverrideRendererColor(copy);
        AdjustSortingOrder(copy);
    }

    private void OverrideRendererColor(GameObject copy)
    {
        ParticleSystemRenderer rend =
            copy.GetComponent<ParticleSystemRenderer>();

        if (rend == null)
        {
            return;
        }

        if (rend.sharedMaterial != null)
        {
            Material mat = new Material(rend.sharedMaterial);
            mat.SetColor("_Color", outlineColor);
            rend.material = mat;
        }
    }

    private void AdjustSortingOrder(GameObject copy)
    {
        ParticleSystemRenderer rend =
            copy.GetComponent<ParticleSystemRenderer>();

        if (rend == null)
        {
            return;
        }

        rend.sortingOrder += sortingOrderOffset;
    }
}
